{"path": "/tmp/sv-ef28b07c00e749388c6fd7ae49a1cc3e/Components/Pages/Board/AddTaskForm.razor", "file_text": "<div class="card mt-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="Save" disabled="@saving">Save</button>
            <button class="btn btn-sm btn-secondary" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<NewTaskModel> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        saving = true;
        await OnSave.InvokeAsync(new NewTaskModel(title.Trim(), assignee.Trim(), priority, dueDate));
        saving = false;
        ResetForm();
    }

    private async Task Cancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);
}
"}

{"path": "/tmp/sv-ef28b07c00e749388c6fd7ae49a1cc3e/Components/Pages/Board/KanbanColumn.razor", "file_text": "<div class="col">
