    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> MoveLeft { get; set; }
    [Parameter] public EventCallback<int> MoveRight { get; set; }
    [Parameter] public EventCallback<AddTaskForm.NewTaskModel> OnTaskAdded { get; set; }

    private bool showForm;

    private async Task HandleSave(AddTaskForm.NewTaskModel model)
    {
        await OnTaskAdded.InvokeAsync(model);
        showForm = false;
    }
}
"}

