@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   TodoCount="TodoTasks.Count"
                   InProgressCount="InProgressTasks.Count"
                   DoneCount="DoneTasks.Count"
                   OverdueCount="OverdueCount" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      MoveRight="id => MoveTask(id, \"In Progress\")"
                      OnTaskAdded="model => AddTask(model, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      MoveLeft="id => MoveTask(id, \"To Do\")"
                      MoveRight="id => MoveTask(id, \"Done\")"
                      OnTaskAdded="model => AddTask(model, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      MoveLeft="id => MoveTask(id, \"In Progress\")"
                      OnTaskAdded="model => AddTask(model, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm)) return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == taskId ? t with { Status = newStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(AddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}

